+unsafe fn regex_buffer_layout(buffer: *mut c_void) -> Option<&'static mut RegexBufferLayout> {
+    if buffer.is_null() {
+        return None;
+    }
+    Some(unsafe { &mut *(buffer as *mut RegexBufferLayout) })
