+fn argz_sep_entries(bytes: &[u8], sep: u8) -> Vec<&[u8]> {
+    let mut entries = Vec::new();
+    let mut pos = 0usize;
+
+    while pos < bytes.len() {
+        while pos < bytes.len() && bytes[pos] == sep {
+            pos += 1;
+        }
+        if pos == bytes.len() {
+            break;
+        }
+
+        let mut end = pos;
+        while end < bytes.len() && bytes[end] != sep {
+            end += 1;
+        }
+        entries.push(&bytes[pos..end]);
+        pos = end;
+    }
+
+    if !bytes.is_empty() && bytes[bytes.len() - 1] == sep {
+        entries.push(&[]);
+    }
+
+    entries
+}
